&lt;h3 dir=&quot;ltr&quot; style=&quot;line-height:1.38;margin-top:14pt;margin-bottom:4pt;&quot;&gt;&lt;span style=&quot;font-size:13pt;font-family:Arial, sans-serif;color:#000000;background-color:transparent;font-weight:bold;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre-wrap;&quot;&gt;T&aacute;i tạo l&agrave;n da v&agrave; gột rửa bụi trần&lt;/span&gt;&lt;/h3&gt;
